241→    path.resolve(__dirname, 'addons/json-editor/register.tsx'),
242→  ],
243→
244→  viteFinal: async config => {
245→    config.plugins = config.plugins || [];
246→    config.plugins.push(tildeResolverPlugin());
247→    config.plugins.push(dtsStubPlugin());
248→    config.plugins.push(circularFixPlugin());
249→    config.plugins.push(jsxInJsPlugin());
250→    config.plugins.push(cjsToEsmPlugin());
251→
252→    config.optimizeDeps = config.optimizeDeps || {};
253→    config.optimizeDeps.include = [
254→      ...(config.optimizeDeps.include || []),
255→      'styled-components',
256→      'styled-components/native',
257→      'card-validator',
258→      'credit-card-type',
