269→
270→    config.resolve = config.resolve || {};
271→    config.resolve.alias = {
272→      ...(config.resolve.alias || {}),
273→      // Native module mocks (no ~/ aliases here — handled by tildeResolverPlugin)
274→      'postcss': path.resolve(__dirname, '../node_modules/postcss/lib/postcss.mjs'),
275→      'react-native-linear-gradient': path.resolve(__dirname, 'mocks/react-native-linear-gradient.tsx'),
